        I_AM_BUSY_WITH_PREPARATIONS_FOR_PRINCESS_CLAIDIE                     = 142,  -- I am busy with preparations for Princess Claidie's coming-of-age ceremony. You don't know what kind of vermin could be roaming the streets and looking for trouble.
        PRINCESS_CLAIDIE_S_COMING_OF_AGE_CEREMONY_IS_2                       = 143,  -- Princess Claidie's coming-of-age ceremony is about to begin at the cathedral. I must remain at my post, but why don't you attend?
