        YOU_HAVE_MATURED_FROM_A_FLEDGLING_ADVENTURER_INTO                    = 145,  -- You have matured from a fledgling adventurer into a great asset to our kingdom. Do not let us down.
        THERE_IS_NO_NEED_FOR_MODESTY_AT_A                                    = 146,  -- There is no need for modesty at a time like this. The fate of San d'Oria is at stake!
