        SHOULD_YOU_UNCOVER_ANY_NEWS_OF_RANPERRE_S                            = 7302,  -- %, should you uncover any news of Ranperre's Treasure, report to us at once.
        FATHER_I_URGE_YOU_TO_SEND_EXPEDITIONS_TO                             = 7303,  -- Father, I urge you to send expeditions to every corner of Vana'diel!
