        HERE_IT_S_NO_MUCH_BUT_THIS_IS                                        = 7416,  -- Here, it's no' much, but this is all I can spare. Take it, then.
        TIS_HARD_FOR_ME_TO_ACCEPT_THAT_THE                                   = 7417,  -- 'Tis hard for me to accept that the fair Queen Leaute's no longer in the world... Now there was a bonny flower, I tell you! The prettiest of them all!
        SHE_ALWAYS_HAD_A_KIND_WORD_EVEN_FOR                                  = 7418,  -- She always had a kind word, even for a lowly gardener such as meself. If Queen Leaute were around, things would be different in this kingdom. Things'd be right, they would!
