        AH_P_PRINCE_PIEUJE_A_AND_YOUR_HOLINESS                               = 7421,  -- Ah! P-Prince Pieuje! A-and Your Holiness!
        YOU_VE_GIVEN_YOUR_BEST_EFFORT_SO_THAT                                = 7422,  -- You've given your best effort so that this garden may prosper, I hear. We owe you our gratitude.
        YET_DO_NOT_PRY_INTO_THE_AFFAIRS_OF                                   = 7423,  -- Yet...do not pry into the affairs of the royal house so. Necks that are stuck where they do not belong have a tendency to...fall off, shall we say.
