        VERY_WELL_I_VE_NO_INTENTION_OF_SPEAKING                              = 7426,  -- Very well. I've no intention of speaking harshly before my late mother.
        NOW_YOUR_HOLINESS_PRAY_FOR_MY_MOTHER_S                               = 7427,  -- Now, Your Holiness, pray for my mother's peaceful rest.
        IT_SEEMS_WE_AVOIDED_THE_WORST_BUT_MY                                 = 7428,  -- It seems we avoided the worst, but my heart quickens. I hope it is naught but my imagination.
        COMMENDABLE_WORK_WITH_OUR_MORTAL_ENEMY_VANQUISHED_WE                 = 7429,  -- Commendable work. With our mortal enemy vanquished, we must now restore glory to San d'Oria. Your cooperation is expected!
        WHAT_IS_IT_HAVE_YOU_SOMETHING_TO_SAY                                 = 7430,  -- What is it? Have you something to say?
        PEOPLE_SPEAK_OF_MY_FATHER_S_GHOST_NOT                                = 7431,  -- People speak of my father's ghost? Not once has anyone mentioned this to me...
        BUT_SUCH_A_RUMOR_TROUBLES_ME_FOR_IT                                  = 7432,  -- But such a rumor troubles me, for it could be him.
        I_WOULD_HAVE_LIKED_YOU_TO_LOOK_INTO                                  = 7433,  -- I would have liked you to look into this matter, but it seems I would sooner get blood from a stone.
        TELL_ME_WOULD_YOU_PLEASE_HEAD_TO_THE                                 = 7434,  -- Tell me, would you please head to the cathedral and investigate?
