        IN_MY_YOUNGER_DAYS_MY_FERVENT_FATHER_OFTEN                           = 7436,  -- In my younger days my fervent father often took me, but I never felt at home there.
        WILL_YOU_GO_OF_COURSE_NOT_RIGHT_NOW                                  = 7437,  -- Will you go? Of course. Not right now.
        THANK_YOU_AND_HERE_TAKE_THIS                                         = 7438,  -- Thank you. And here, take this.
