        AND_THEN_COME_BACK_AND_TELL_ME_HOW                                   = 7461,  -- And then come back and tell me how you fared. Even a little information could help solve the puzzle of my father's death.
        SO_THE_GREAVES_WERE_MADE_FOR_RED_MAGES                               = 7462,  -- So the greaves were made for red mages... Perhaps it was my father in the cathedral.
        BUT_WHY_THAT_PLACE_COULD_HE_BE_TRYING                                = 7463,  -- But why that place? Could he be trying to convey something to me? If only I could hear his message.
        I_REALIZE_I_VE_ASKED_MANY_FAVORS_OF                                  = 7464,  -- I realize I've asked many favors of you, but I yearn to put this matter to rest. Will you investigate in my stead?
        WILL_YOU_INVESTIGATE_OF_COURSE_I_WILL_I                              = 7465,  -- Will you investigate? Of course I will. I'm afraid not.
        WHY_THANK_YOU_I_HAVE_NO_GUIDANCE_TO                                  = 7466,  -- Why, thank you! I have no guidance to give you, so you must stand on your own two feet.
