        PRINCE_TRION_PREFERS_ELVAAN_GIRLS_WITH_BLACK_HAIR                    = 8084,  -- Prince Trion prefers Elvaan girls with black hair braided behind the left ear.
        PRINCE_TRION_PREFERS_ELVAAN_GIRLS_WITH_SILVER_HAIR                   = 8085,  -- Prince Trion prefers Elvaan girls with silver hair braided behind the left ear.
        PRINCE_TRION_PREFERS_TARUTARU_GIRLS_WITH_RED_HAIR                    = 8086,  -- Prince Trion prefers Tarutaru girls with red hair parted in the front, and tied back in a ponytail.
        PRINCE_TRION_PREFERS_TARUTARU_GIRLS_WITH_REDDISH_BLONDE              = 8087,  -- Prince Trion prefers Tarutaru girls with reddish-blonde hair parted in the front, and tied back in a ponytail.
