        WHEN_IN_POSSESSION_OF_THE_KEY_ITEM_TEMPORARY                         = 8248,  -- When in possession of the key item %, temporary items will be automatically added to the player's inventory when quarried.
        WHEN_A_PLAYER_S_INVENTORY_EXCEEDS_THE_MAXIMUM                        = 8249,  -- When a player's inventory exceeds the maximum capacity, any temporary item found will simply be discarded. You can speak to me to borrow or return the shovel at any time.
        BORROW_THE_YES_NO                                                    = 8250,  -- Borrow the %? Yes. No.
        RETURN_THE_YES_NO_3                                                  = 8251,  -- Return the %? Yes. No.
        WHEN_IN_POSSESSION_OF_THE_KEY_ITEM_YOU                               = 8252,  -- When in possession of the key item %, you will have the choice of keeping or throwing away the first Petra you quarry. You will also retain the ability to sprint.
        YOU_CAN_SPEAK_TO_ME_TO_BORROW_OR                                     = 8253,  -- You can speak to me to borrow or return the band at any time.
        SELECT_A_MATCH_LEVEL_VIEW_ALL_LEVELS_NO                              = 8254,  -- Select a match level... View all levels. No restriction (# gil per match). Level 60 (# gil per match). Level 50 (# gil per match). Level 40 (# gil per match). Level 30 (# gil per match). Return.
        SELECT_FOR_MORE_INFORMATION_NEXT_RETURN                              = 8255,  -- Select for more information... , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. % / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] Next. Return.
        MATCH_ENTRY_PERIOD_BEGINS_BRIEFING_BEGINS                            = 8256,  -- <Match #> Entry period begins: Briefing begins:
        I_APOLOGIZE_BUT_YOUR_LEVEL_IS_TOO_LOW                                = 8257,  -- I apologize, but your level is too low to participate in an official Brenner match.
        OFFICIAL_MATCHES_ARE_SCHEDULED_TO_BEGIN_AT_THE                       = 8258,  -- Official matches are scheduled to begin at the following times: Match 1: Match 2: Match 3:
        TELEPORTATION_TO_THE_ISLE_IS_FREE_OF_CHARGE                          = 8259,  -- Teleportation to the Isle is free of charge, but a participation fee of # gil is required before each match.
        TRAVEL_TO_THE_ISLE_YES_NOT_YET                                       = 8260,  -- Travel to the Isle? Yes. Not yet.
        WHAT_WOULD_YOU_LIKE_TO_KNOW_ABOUT_BASIC                              = 8261,  -- What would you like to know about? Basic rules. Official/private matches. Flammen-Brenner. Flamme. Match score. Petras and quarrying. Sprint. KO. Return.
        THE_BASIC_RULES_OF_BRENNER_ARE_AS_FOLLOWS                            = 8262,  -- The basic rules of Brenner are as follows:
        FIRST_THE_PARTICIPANTS_DIVIDE_INTO_TWO_TEAMS_EACH                    = 8263,  -- First, the participants divide into two teams. Each side's camp contains the same number of Flammen-Brenner.
        AT_THE_BEGINNING_OF_THE_MATCH_HALF_OF                                = 8264,  -- At the beginning of the match, half of each side's Flammen-Brenner will be ablaze with Flamme, or flame, while the other half will remain unlit.
        PARTICIPANTS_CAN_SEIZE_A_FLAMME_FROM_THE_OPPOSING                    = 8265,  -- Participants can seize a Flamme from the opposing side's Flammen-Brenner and carry it around the Isle.
        THE_GOAL_IS_TO_STEAL_YOUR_OPPONENT_S                                 = 8266,  -- The goal is to steal your opponent's Flamme and use them to light your side's Flammen-Brenner.
        THE_SIDE_THAT_SUCCEEDS_IN_LIGHTING_ALL_OF                            = 8267,  -- The side that succeeds in lighting all of its Flammen-Brenner will be declared the winner after a specified amount of time.
        IF_NEITHER_SIDE_IS_VICTORIOUS_BEFORE_THE_MATCH                       = 8268,  -- If neither side is victorious before the match ends, the outcome will be judged based on the score. The match score section of the rulebook contains more information on this subject.
        BRENNER_IS_SIGNIFICANTLY_DIVIDED_INTO_PUBLIC_AND_PRIVATE             = 8269,  -- Brenner is significantly divided into public and private matches. Official matches are held periodically according to level and feature general participation.
        YOU_CANNOT_RESERVE_THE_ISLE_WHEN_AN_OFFICIAL                         = 8270,  -- You cannot reserve the Isle when an official match is being held.
        NO_ITEMS_ARE_NECESSARY_FOR_PARTICIPATION_BUT_A                       = 8271,  -- No items are necessary for participation, but a minor fee will be collected. You will be unable to participate if your level is too low.
        THE_MATCH_OUTCOME_WILL_BE_RECORDED_UNLESS_THE                        = 8272,  -- The match outcome will be recorded unless the number of participants fails to exceed # members, or if there are fewer than # members in a match where the two sides' numbers differ. In such cases, the game will be considered a training match and will not be recorded.
        PRIVATE_MATCHES_REQUIRE_A_RESERVATION_AND_PARTICIPATION_MAY          = 8273,  -- Private matches require a reservation, and participation may be limited. The Master of Ceremonies (MC) can freely adjust the rules and control match proceedings.
        LS_LIGA_IS_A_FORM_OF_PRIVATE_MATCH                                   = 8274,  -- LS Liga is a form of private match. You can learn more about LS Liga by speaking to a Marshal.
        A_FLAMMEN_BRENNER_IS_A_DEVICE_THAT_CONTAINS                          = 8275,  -- A Flammen-Brenner is a device that contains a Flamme (flame). The Flammen-Brenner is covered by a grate that will open after taking a set amount of damage, exposing the Flamme.
        THE_PARTICIPANTS_MUST_UTILIZE_THIS_CHANCE_TO_SEIZE                   = 8276,  -- The participants must utilize this chance to seize the Flamme before the grate recloses. Once the grate is closed, the Flammen-Brenner will begin recovering from the damage it has been dealt.
        IF_YOU_MANAGE_TO_OPEN_THE_OPPOSING_TEAM                              = 8277,  -- If you manage to open the opposing team's Flammen-Brenner and capture their Flamme, you should make haste to light one of the Flammen-Brenner on your side.
        AFTER_A_CERTAIN_AMOUNT_OF_TIME_THE_FLAMME                            = 8278,  -- After a certain amount of time, the Flamme will burn out and the opposing team's Flammen-Brenner will be relit.
        ALSO_PLEASE_NOTE_THAT_YOU_CANNOT_QUICKEN_YOUR                        = 8279,  -- Also, please note that you cannot quicken your pace using any special abilities while you are in possession of a Flamme.
        IN_THE_EVENT_THAT_NEITHER_SIDE_FULFILLS_THE                          = 8280,  -- In the event that neither side fulfills the conditions for victory, the outcome of the match will be evaluated based on score.
        TEN_POINTS_ARE_AWARDED_TO_EACH_SIDE_FOR                              = 8281,  -- Ten points are awarded to each side for every lit Flammen-Brenner, while one point is awarded whenever a Flamme is captured, used to light a Flammen-Brenner, or recaptured from an opponent. One point is also awarded for protecting the Flammen-Brenner for a certain period of time.
        LIKE_BALLISTA_QUARRY_QUARRY_CAN_BE_USED_WHILE                        = 8282,  -- Like Ballista, quarry (/quarry) can be used while playing Brenner. Participants may use this ability to dig up Petras and temporary items.
        HOWEVER_UNLIKE_BALLISTA_PETRAS_BRENNER_PETRAS_HAVE_NO                = 8283,  -- However, unlike Ballista Petras, Brenner Petras have no effect on the match score. You can trade a Petra to a Pursuivant to recover your HP and MP at no expense to TP.
        SPRINT_CANNOT_BE_USED_WHILE_CARRYING_A_PETRA                         = 8284,  -- Sprint cannot be used while carrying a Petra. Also, please note that the scout ability cannot be used in Brenner.
        PETRAS_WILL_BE_LOST_IN_THE_EVENT_OF                                  = 8285,  -- Petras will be lost in the event of a KO, but can be carried over from one match to another.
        THE_SPRINT_SPRINT_ABILITY_CAN_BE_USED_TO                             = 8286,  -- The sprint (/sprint) ability can be used to increase the player's speed when not in possession of a Flamme or Petras.
        IN_THE_EVENT_OF_A_KO_YOU_WILL                                        = 8287,  -- In the event of a KO, you will be returned to your team's camp. However, recovery will take longer the more often you fall in battle.
        IN_OTHER_WORDS_YOU_WILL_RECEIVE_A_PENALTY                            = 8288,  -- In other words, you will receive a penalty if you fall immediately after recovering from KO. In addition, your TP will be reduced to zero and you will lose any Petras in your possession.
        I_M_SORRY_I_WASN_T_LISTENING_COULD                                   = 8289,  -- I'm sorry. I wasn't listening. Could you start over from the beginning?
        S_BADGE_FLASHES_BRIGHTLY                                             = 8290,  -- %'s badge flashes brightly.
        IT_APPEARS_THE_EMPIRE_OF_AHT_URHGAN_IS                               = 8291,  -- It appears the Empire of Aht Urhgan is desperate to recruit mercenaries. I assume that is the function of the badge you wear?
        AND_HOW_WOULD_I_KNOW_SUCH_A_THING                                    = 8292,  -- And how would I know such a thing, you ask? Through the now ruined nation of Tavnazia, San d'Oria once had much traffic with the Near East.
        THOSE_TIES_PERSIST_TO_THIS_DAY_AND_WE                                = 8293,  -- Those ties persist to this day, and we yet maintain a perfunctory level of international diplomacy. All manner of information makes its way to my ears.
        HOWEVER_THERE_IS_ONE_THING_I_STRUGGLE_TO                             = 8294,  -- However, there is one thing I struggle to understand. Why would a nation with enough military power to have her neighbors trembling in fear need to ask for assistance...?
        A_BADGE_OF_THAT_DESPICABLE_MERCENARY_OUTFIT_IN                       = 8295,  -- A badge of that despicable mercenary outfit in here? You show a surprising lack of discretion, adventurer.
        OR_SO_I_SHOULD_LIKE_TO_SAY_TO                                        = 8296,  -- Or so I should like to say to even my own knights. There are those within our ranks that have felt the lure of mercenary wages.
        I_WOULD_HOPE_THEIR_OATHS_AS_PROTECTORS_OF                            = 8297,  -- I would hope their oaths as protectors of the Kingdom were taken more seriously. No matter--I am certain this temptation will strike but once, then leave our knights stronger for the experience.
        IS_THAT_ONE_OF_THOSE_NEAR_EASTERN_BADGES                             = 8298,  -- Is that one of those Near Eastern badges!? Remove it at once! If Prince Trion were to see you wearing one of those...
        SEEING_ALL_THESE_PEOPLE_SPORTING_MERCENARY_BADGES_HAS                = 8299,  -- Seeing all these people sporting mercenary badges has him in a volatile mood.
        YOU_WEAR_A_BADGE_OF_THE_LAND_OF                                      = 8300,  -- You wear a badge of the land of Aht Urhgan.
        QUEEN_LEAUTE_BROUGHT_MANY_PLANTS_FROM_HER_HOMELAND                   = 8301,  -- Queen Leaute brought many plants from her homeland of Tavnazia to fill this garden, including a few that originated in the Near East.
        THAT_ONE_THERE_WITH_THE_LARGE_FLOWERS_IS                             = 8302,  -- That one there with the large flowers is such a specimen. I hear they enhance the blooms with alchemical processes.
        EVER_SINCE_THAT_RECRUITER_FROM_AHT_URHGAN_ARRIVED                    = 8303,  -- Ever since that recruiter from Aht Urhgan arrived, the chateau has been in an uproar. Especially Prince Tri--
        BE_ON_YOUR_WAY_ADVENTURER_I_LL_THANK                                 = 8304,  -- Be on your way, adventurer. I'll thank you to forget what you have heard here.
        SO_YOU_ARE_THE_GUARDS_TELL_ME_YOU                                    = 8305,  -- So, you are %. The guards tell me you were the one to deliver this letter...
        AS_YOU_ARE_LIKELY_AWARE_ALL_MATTERS_CONCERNING                       = 8306,  -- %. As you are likely aware, all matters concerning the royal family pass through me.
        SHOW_HIM_OF_COURSE_NOT_A_CHANCE                                      = 8307,  -- Show him %? Of course. Not a chance.
        HMMM_I_HAD_HEARD_THAT_THE_EMPIRE_OF                                  = 8308,  -- Hmmm. I had heard that the Empire of Aht Urhgan was desperately recruiting mercenaries, but to see one of their insignias with my own eyes...
        YOU_HAVE_BECOME_A_MERCENARY_HAVE_YOU_NOT                             = 8309,  -- %, you have become a mercenary, have you not?
        WHAT_HAVE_WE_HERE                                                    = 8310,  -- What have we here?
        A_LETTER_WITH_WRITING_SO_TERRIBLE_I_CANNOT                           = 8311,  -- A letter...with writing so terrible I cannot even read that I am the intended recipient.
        THIS_CARRION_WORM_SCRAWL_I_HAVE_SEEN_ITS                             = 8312,  -- This carrion worm scrawl... I have seen its like before...
        THE_PERSON_WHO_ENTRUSTED_YOU_WITH_THIS_MESSAGE                       = 8313,  -- The person who entrusted you with this message...
        THE_LORD_OF_ILLEGIBILITY_AS_I_WOULD_CALL                             = 8314,  -- The Lord of Illegibility, as I would call him...
        AHAHA_I_SHOULD_NOT_SAY_SUCH_THINGS_OF                                = 8315,  -- Ahaha... I should not say such things of our dear prince...
        THOUGH_I_AM_CORRECT_AM_I_NOT                                         = 8316,  -- Though I am correct, am I not...?
        THIS_LETTER_IS_FROM_THE_HEIR_TO_THE                                  = 8317,  -- This letter is from the heir to the throne of San d'Oria, the Prince Royal, Trion I d'Oraguille!
        ID_8318                                                              = 8318,  -- !?
        IT_CANNOT_BE_THAT_AWFUL_PENMANSHIP                                   = 8319,  -- It cannot be... That awful penmanship...
        I_AM_CERTAIN_THIS_LETTER_IS_FROM_THE                                 = 8320,  -- I am certain... This letter is from the heir to the throne of San d'Oria, the Prince Royal, Trion I d'Oraguille!
        I_AM_MISTAKEN_YOU_SAY                                                = 8321,  -- I am mistaken, you say?
        THIS_LETTER_WAS_WRITTEN_BY_ONE_SAGE_RAILLEFAL                        = 8322,  -- This letter was written by one Sage Raillefal? But this chocobo scratch could only be the work of Prince Trion...
        I_SHALL_PROVE_IT_TO_YOU_I_HAVE                                       = 8323,  -- I shall prove it to you. I have long attended to the prince and encountered many opportunities to decipher his...unique...style of writing...
        A_MOMENT_IF_YOU_WILL                                                 = 8324,  -- A moment, if you will...
        ID_8325                                                              = 8325,  -- ...
        ID_8326                                                              = 8326,  -- ???
        ASTRIL_CONDES_ASTRUL_WAND_UAR                                        = 8327,  -- Astril Condes...? Astrul Wand...? Uar...?
        THIS_TRULY_IS_ATROCIOUS                                              = 8328,  -- This truly is atrocious...
        I_HAVE_NO_DOUBT_THIS_LETTER_IS_FROM                                  = 8329,  -- I have no doubt this letter is from Prince Trion!
        BUT_I_AM_AFRAID_I_CANNOT_MAKE_OUT                                    = 8330,  -- But I am afraid I cannot make out the meaning...
        MONARLAIS_HALVER_YOU_LOOK_TROUBLED_PERHAPS_I_MAY                     = 8331,  -- Monarlais Halver. You look troubled. Perhaps I may be of assistance?
        GENERAL_RAHAL_YOUR_OFFER_OF_AID_IS_MOST                              = 8333,  -- General Rahal. Your offer of aid is most generous, however...
        NO_NEED_TO_BE_SO_HUMBLE_YOU_HAVE                                     = 8334,  -- No need to be so humble. You have one of Trion's indecipherable letters, do you not?
        HOW_COULD_YOU_KNOW                                                   = 8335,  -- How could you know...?
        I_HAVE_MY_SOURCES                                                    = 8336,  -- I have my sources...
        SOME_DAYS_AGO_PRINCE_TRION_ABANDONED_THE_SIGNING                     = 8337,  -- Some days ago, Prince Trion abandoned the signing of some official documents...
        HE_PLACED_A_MANNEQUIN_IN_HIS_CHAIR_AND                               = 8338,  -- He placed a mannequin in his chair, and fled the chateau in the dead of night...
        AT_LEAST_IT_WAS_NOT_A_FOREST_HARE                                    = 8339,  -- At least it was not a forest hare this time...
        THAT_IS_WHEN_I_HAD_TRAVIALCE_HERE_SHADOW                             = 8340,  -- That is when I had Travialce here shadow the prince's movements. He has had training in the arts of the ninja.
        PLEASE_CONTINUE_THE_TALE_TRAVIALCE                                   = 8341,  -- Please continue the tale, Travialce.
        SIR_PRINCE_TRION_FIRST_MADE_HIS_WAY_TO                               = 8342,  -- Sir. Prince Trion first made his way to Mhaura and passed himself off as an adventurer.
        DEAR_ALTANA_A_MEMBER_OF_THE_ROYAL_FAMILY                             = 8343,  -- Dear Altana... A member of the royal family traipsing about as an adventurer...
        THE_COURT_WILL_BE_MORTIFIED                                          = 8344,  -- The court will be mortified.
        FROM_THERE_HIS_HIGHNESS_BOARDED_A_FERRY_BOUND                        = 8345,  -- From there, His Highness boarded a ferry bound for the shores of Aht Urhgan...
        AHT_URHGAN_AND_THEN                                                  = 8346,  -- Aht Urhgan!? And then?
        I_QUICKLY_SLIPPED_ABOARD_AS_WELL_AND_GUARDED                         = 8347,  -- I quickly slipped aboard as well, and guarded the royal person from the shadows.
        THE_FERRY_SAFELY_ARRIVED_IN_AL_ZAHBI_WITH                            = 8348,  -- The ferry safely arrived in Al Zahbi with the prince none the wiser of my presence.
        AFTER_ENTERING_THE_CITY_PRINCE_TRION_HEADED_STRAIGHT                 = 8349,  -- After entering the city, Prince Trion headed straight to a mercenary company and apparently signed some sort of contract.
        A_CONTRACT_SURELY_NOT_WITH_HIS_OWN_NAME                              = 8350,  -- A contract!? Surely not with his own name? This could escalate into an international crisis!
        THERE_IS_NOTHING_TO_FEAR_ON_THAT_COUNT                               = 8351,  -- There is nothing to fear on that count. His Highness travels the Empire under the assumed name of Raillefal.
        SO_NO_ONE_IN_AL_ZAHBI_IS_AWARE                                       = 8352,  -- So no one in Al Zahbi is aware of his true identity?
        I_WOULDN_T_SAY_THAT_MILORD_THE_PRINCE                                = 8353,  -- I wouldn't say that, milord... The prince is wearing a suit of gilded gold plate and is not subtle in his information gathering.
        GREAT_GODDESS_THEN_HE_IS_NOT_DISGUISED_AT                            = 8354,  -- Great Goddess... Then he is not disguised at all?
        NO_MILORD                                                            = 8355,  -- No, milord.
        COME_TO_THINK_OF_IT_I_HAVE_SEEN                                      = 8356,  -- Come to think of it, I have seen this adventurer's face in the very same mercenary company...
        THIS_LETTER_MUST_BE_THE_VERY_SAME_DOCUMENT                           = 8357,  -- This letter must be the very same document I witnessed in the prince's hand at the Shararat Teahouse.
        I_AM_WOUNDED_THAT_PRINCE_TRION_DOES_NOT                              = 8358,  -- I am wounded that Prince Trion does not have more trust in us, his loyal subjects...
        AND_I_DO_WISH_HE_WOULD_ACT_WITH                                      = 8359,  -- And I do wish he would act with a little more discretion.
        THAT_IS_A_MATTER_WE_SHALL_DISCUSS_ANON                               = 8360,  -- That is a matter we shall discuss anon...
        FIRST_WE_MUST_LEARN_THE_REASON_FOR_PRINCE                            = 8361,  -- First, we must learn the reason for Prince Trion's seemingly frequent trips to the nation of Aht Urhgan.
        WHAT_IS_THE_CURRENT_STATE_OF_THE_NEAR                                = 8362,  -- What is the current state of the Near East? Is the prince in any danger?
        DO_NOT_BE_CONCERNED                                                  = 8363,  -- Do not be concerned.
        I_AM_SURE_THAT_TRAVIALCE_HAS_LEARNED_MUCH                            = 8364,  -- I am sure that Travialce has learned much from following the prince. Please enlighten us.
        SIR_RAILLEFAL_AH_PRINCE_TRION_INVESTIGATED_THE_FOLLOWING             = 8365,  -- Sir. Raillefal...ah, Prince Trion, investigated the following facts.
        FOUR_YEARS_AGO_JALZAHN_THE_FORMER_EMPEROR_OF                         = 8366,  -- Four years ago, Jalzahn, the former Emperor of Aht Urhgan, and his wife both succumbed to the same illness...
        YES_I_REMEMBER_THE_KINGDOM_OF_SAN_D                                  = 8367,  -- Yes, I remember... The Kingdom of San d'Oria sent her condolences. The illness was quite virulent, as I recall...
        THE_BEASTMEN_WHO_DWELL_ON_THE_WESTERN_BORDERS                        = 8368,  -- The beastmen who dwell on the western borders of the nation used this as an opportunity to cease offering tributes.
        HMPH_WHAT_MORE_WOULD_YOU_EXPECT_FROM_THOSE                           = 8369,  -- Hmph. What more would you expect from those savages?
        THOUGH_THE_EMPIRE_S_LONG_WAR_WITH_THE                                = 8370,  -- Though the Empire's long war with the eastern nations was at a stalemate, they could not afford to grow complacent.
        THE_MAIN_BODY_OF_THE_IMPERIAL_ARMY_REMAINED                          = 8371,  -- The main body of the Imperial Army remained focused on the east...
