        WELL_MET_FRIEND_I_AM_TEMPLE_KNIGHT_REMBARD                           = 8440,  -- Well met, friend. I am Temple Knight Rembard. My duty is the issuance of marriage certificates to lawfully wedded couples.
        HOW_MAY_I_SERVE_YOU_THIS_DAY                                         = 8441,  -- How may I serve you this day?
        MARRIAGE_CERTIFICATES_ARE_LEGALLY_BINDING_DOCUMENTS_ISSUED_IN        = 8442,  -- Marriage certificates are legally binding documents issued in recognition of the matrimony of the two individuals named therein. They may also adorn the wall of your Mog House.
        THOSE_WISHING_TO_RECEIVE_THIS_DOCUMENT_MUST_PRESENT                  = 8443,  -- Those wishing to receive this document must present proof of their marriage in the manner I shall now explain.
        THE_COUPLE_SHOULD_FORM_A_PARTY_WHILE_THE                             = 8444,  -- The couple should form a party while the husband is equipped with his matrimony ring, and his wife, her matrimony band. Thence, speak to me, and I shall prepare the certificates without delay.
