        PLEASE_BEAR_IN_THE_MIND_THOUGH_THAT_ONE                              = 8446,  -- Please bear in the mind, though, that one person cannot possess multiple certificates at any given time. Furthermore, the nation of issuance for the certificate you hold cannot differ from that of your spouse.
        LASTLY_THE_RE_ISSUANCE_OF_A_MISPLACED_CERTIFICATE                    = 8447,  -- Lastly, the re-issuance of a misplaced certificate can be carried out solely by the officiating body wherefrom it was originally issued.
        A_WEDDING_IS_A_JOYOUS_EVENT_WHEREIN_TWO                              = 8448,  -- A wedding is a joyous event wherein two souls brought together by fate are joined in an everlasting union.
        SAN_D_ORIAN_TRADITION_HOLDS_THAT_THE_BRIDE                           = 8449,  -- San d'Orian tradition holds that the bride and groom, each with weapon in hand, swear an oath of lifelong loyalty to each other before the goddess Altana.
        WEDDING_RINGS_A_MATRIMONY_RING_AND_A_MATRIMONY                       = 8450,  -- Wedding rings--a matrimony ring and a matrimony band, to be precise--are required.
        THESE_RINGS_WHICH_REQUIRE_RARE_AND_OFTTIMES_ELUSIVE                  = 8451,  -- These rings, which require rare and ofttimes elusive ingredients for synthesis, symbolize a couple's undying devotion to each other.
        PRIOR_TO_PRESENTING_THE_RING_TO_YOUR_PARTNER                         = 8452,  -- Prior to presenting the ring to your partner, it is common practice to engrave one's name onto it using such items as cyclone crystals.
        WEDDING_DRESSES_AND_BENEDIGHT_COATS_POPULARLY_SERVE_AS               = 8453,  -- Wedding dresses and benedight coats popularly serve as ceremonial attire for men and women, respectively.
        WHILE_GARMENTS_LIKE_IN_FORM_AND_FUNCTION_CAN                         = 8454,  -- While garments like in form and function can be synthesized, the procurement of ingredients to make them presents quite a challenge. It is precisely for this reason, however, that significance is lent to their donning in ceremonies. Some adventurers perform the synthesis themselves, while others prefer to entrust the task to a friend.
        BE_NOT_DISHEARTENED_THOUGH_SHOULD_THE_GARMENTS_BE                    = 8455,  -- Be not disheartened, though, should the garments be not within your means. No law dictates how couples must attire themselves in a wedding ceremony.
