        SUCH_ITEMS_AS_FIREWORKS_AND_WEDDING_BELLS_ARE                        = 8457,  -- Such items as fireworks and wedding bells are also available to assist you in enhancing the atmosphere of revelry. You may purchase them as you see fit.
        IT_SEEMS_YOU_ALREADY_HAVE_A_MARRIAGE_CERTIFICATE                     = 8458,  -- It seems you already have a marriage certificate in your possession. I am not authorized to issue you another.
