        YES_MY_LORD_3                                                        = 8494,  -- Yes, my lord.
        THE_RESEMBLANCE_YOU_BEAR_TO_SOMEONE_I_FOUGHT                         = 8495,  -- The resemblance you bear to someone I fought beside during the war is...truly striking. An endearing young lady she was, with such strength of spirit as would make one believe naught was beyond hope.
        TIS_MERELY_BUT_A_TRICK_OF_THE_MIND                                   = 8496,  -- 'Tis merely but a trick of the mind, surely, for two decades have passed since then. Were we to meet this day, she would stand before me a stately matron.
