        SO_THE_SERPENT_WOULD_SEEK_THE_AID_OF                                 = 8505,  -- ...So the serpent would seek the aid of the lion. A curious turn of events, indeed. I must deliver this to my king at once. Come along.
        SO_THE_SERPENT_WOULD_SEEK_THE_AID_OF_2                               = 8506,  -- ...So the serpent would seek the aid of the lion. A curious turn of events, indeed. I must deliver this to my king at once. Come along.
        AN_IRON_GIANT_WITH_THE_POWER_TO_SMITE                                = 8507,  -- An iron giant with the power to smite an airship from the sky, and a young Empress who would nonetheless seek to restore its power...
        ID_8508                                                              = 8508,  -- ...
        I_WOULD_HEAR_YOUR_COUNSEL_HALVER                                     = 8509,  -- I would hear your counsel, Halver.
        YOUR_HIGHNESS_I_MUST_CONFESS_MY_HEART_MISGIVES                       = 8510,  -- Your Highness. I must confess, my heart misgives me as to the wisdom of this endeavor...
        HALVER_2                                                             = 8511,  -- Halver...!
