        BEGGING_YOUR_PARDON_MY_PRINCE_I_DARESAY_THAT                         = 8515,  -- Begging your pardon, my prince. I daresay that the mere fact that they seek our consent--rather than engaging in devious and furtive plots--shows that we deal no longer with the Silent Empire of old.
        SETTLE_YOURSELF_HALVER_I_SAID_NOTHING_OF_DENYING                     = 8516,  -- Settle yourself, Halver. I said nothing of denying their plea.
        FORGIVE_ME_MY_PRINCE_I_SPOKE_IN_HASTE                                = 8517,  -- Forgive me, my prince. I spoke in haste.
