        I_COULD_NOT_AGREE_MORE_MY_KING                                       = 8522,  -- I could not agree more, my king.
        HAS_SERVED_THE_KINGDOM_WITH_LOYALTY_AND_VALOR                        = 8523,  -- % has served the Kingdom with loyalty and valor time and again.
        I_TOO_CAN_VOUCH_FOR_THIS_FATHER                                      = 8524,  -- I, too, can vouch for this, Father.
        I_HAVE_FOUGHT_BY_S_SIDE_AND_YOU                                      = 8525,  -- I have fought by %'s side, and you will find no comrade more honorable.
        THE_KINGDOM_IS_SAFE_IN_HIS_HER_HANDS                                 = 8526,  -- The Kingdom is safe in his/her] hands, Father.
        VERY_WELL                                                            = 8527,  -- Very well.
        HALVER_AND_MY_SONS_PRESENT_A_COMPELLING_CASE                         = 8528,  -- Halver and my sons present a compelling case. Return to this Empress, and tell her San d'Oria stands with her. Now farewell, and may the Goddess watch over your journey!
        BESIDES_WERE_SOMETHING_TO_GO_AMISS_THE_PRESENCE_2                    = 8529,  -- Besides, were something to go amiss, the presence of % here should suffice to keep matters in hand.
        HALVER_AND_MY_SON_PRESENT_A_COMPELLING_CASE                          = 8530,  -- Halver and my son present a compelling case. Return to this Empress, and tell her San d'Oria stands with her. Now farewell, and may the Goddess watch over your journey!
        GREETINGS_I_MUST_SAY_THAT_OUTFIT_TRULY_BECOMES                       = 8531,  -- Greetings, %. I must say, that outfit truly becomes you.
        WELL_MET_ADVENTURER_I_MUST_SAY_THAT_OUTFIT                           = 8532,  -- Well met, adventurer. I must say, that outfit truly becomes you.
        YOU_SHOULD_KNOW_THAT_YOUR_EXPLOITS_HAVE_IMPRESSED                    = 8533,  -- You should know that your exploits have impressed many a knight, so much so that those have emerged who would forsake their Kingdom for an unfettered life. It troubles me to imagine a San d'Oria bereft of those who would charge into battle in her defense.
