        WHY_WOULD_YOU_NEED_MY_FORGIVENESS                                    = 8574,  -- Why would you need my forgiveness?
        W_WAIT_I_IT_IS_NOT_WHAT_YOU                                          = 8575,  -- W-wait! I-it is not what you think!
