        WHO_GOES_THERE_2                                                     = 8579,  -- Who goes there?
        AH_I_DID_NOT_EXPECT_YOUR_PRESENCE_THIS                               = 8580,  -- Ah, %! I did not expect your presence this day.
        YOU_NEED_NOT_SAY_MORE_HAS_FOUND_ITS                                  = 8581,  -- You need not say more. % has found its way into your possession, has it not?
        THE_NATURAL_CONCLUSION_THEN_IS_THAT_YOU_DESIRE                       = 8582,  -- The natural conclusion, then, is that you desire that my alter ego accompany you into battle.
        I_MUST_ADMIT_THE_IDEA_IS_NOT_WITHOUT                                 = 8583,  -- I must admit the idea is not without merit.
        MY_RESPONSIBILITIES_HERE_AT_THE_CHATEAU_HAVE_KEPT                    = 8584,  -- My responsibilities here at the chateau have kept me overlong from the front lines. How I long to remind San d'Oria's enemies to fear the name Trion I d'Oraguille!
        YET_BOTH_NEEDS_MAY_BE_SERVED_WHILE_I                                 = 8585,  -- Yet both needs may be served. While I tend to my duties here, my alter ego may mete out justice abroad. What say you? Will you have me as a companion in your crusades?
