        BUT_WHY_SHOULD_OTHERS_THROUGHOUT_THE_REST_OF                         = 8591,  -- But why should others throughout the rest of the world remain unguided? No, I must work to ensure that those of all upbringings are free from tyranny!
        ALAS_ATTENDING_AFFAIRS_ABROAD_MEANS_NEGLECTING_AFFAIRS_OF            = 8592,  -- Alas, attending affairs abroad means neglecting affairs of state...or so I thought. The institute's announcement has granted me a means to be in multiple places at once.
        HOWEVER_THERE_ARE_THOSE_OF_MY_HOUSE_WHO                              = 8593,  -- However, there are those of my house who have balked at the suggestion.
        THOUGH_IT_WAS_BY_THE_HANDS_OF_ADVENTURERS                            = 8594,  -- Though it was by the hands of adventurers that the Shadow Lord met his demise, it would be unseemly for one of royal lineage to be seen under the employ of one who spends weeks on end defecating in the woods.
