        AND_IF_THEY_CONTINUE_TO_HOWL_I_SHALL                                 = 8598,  -- And if they continue to howl, I shall remind them of how it was you who brought peace to San d'Oria.
        PERHAPS_THEN_THEY_WILL_RECALL_THE_INCIDENT_OF                        = 8599,  -- Perhaps then they will recall the incident of the Lightbringer. Without your intervention, our house would doubtlessly have been more shamed than anything I could personally do.
